const body = $input.all()[0].json.body;
const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;

if (!uuidRegex.test(body.tenantId)) {
  throw new Error('Invalid tenantId format');
}

if (!uuidRegex.test(body.facturxId)) {
  throw new Error('Invalid facturxId format');
}

const plateforme = body.plateforme || 'PPF';
if (!['PPF', 'PDP'].includes(plateforme)) {
  throw new Error('Invalid plateforme: must be PPF or PDP');
}

return {
  tenantId: body.tenantId,
  facturxId: body.facturxId,
  plateforme: plateforme
};

const facturx = $input.all()[0]?.json?.[0];

if (!facturx) {
  throw new Error('Factur-X not found');
}

const generatedId = 'PPF_' + Date.now() + '_' + Math.random().toString(36).substr(2, 9);

const payload = {
  facturxId: facturx.id,
  numeroFacture: facturx.facture_id,
  format: facturx.format,
  profil: facturx.profil,
  xmlContent: facturx.xml_content,
  timestamp: new Date().toISOString(),
  plateforme: $json.plateforme
};

return {
  ...($json),
  facturx: facturx,
  payload: payload,
  identifiantPpf: generatedId,
  transactionId: Math.random().toString(36).substr(2, 9)
};

const result = $input.all()[0]?.json?.[0] || {};

return {
  success: true,
  message: 'Factur-X transmise avec succès',
  facturxId: $json.facturxId,
  plateforme: $json.plateforme,
  identifiantPpf: $json.identifiantPpf,
  dateTransmission: new Date().toISOString(),
  statut: result.statut
};
